public static void main(Args _args)
{
ETGCanadaParameters parameters = ETGCanadaParameters::find();

if (parameters.EnableUninvoicedPackingSlipReport == NoYes::No)
    {
        warning("Uninvoiced Packing Slip Report is disabled in parameters.");
        return;
    }

  ETGUninvoicedPackingSlipController controller = new ETGUninvoicedPackingSlipController();
    controller.parmArgs(_args);
    controller.parmReportName(ssrsReportStr(ETGUninvoicedPackingSlipReport,PackingSlip));
   controller.startOperation();
}
